// =====================================================
// PCMS Service Worker (next-pwa fallback for dev mode)
// In production, this is generated by next-pwa based on next.config.js
// For dev (when SW is disabled), we provide a minimal stub so manifest works
// =====================================================

// Minimal dev-mode Service Worker
// In production, next-pwa replaces this with a full Workbox-based SW
self.addEventListener('install', (event) => {
  // Skip waiting to activate immediately
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  // Take control of all pages immediately
  event.waitUntil(self.clients.claim());
});

self.addEventListener('fetch', (event) => {
  // Pass through all requests — no caching in dev mode
  // (next-pwa handles production caching)
  return;
});

// Handle push notifications (for future Web Push implementation)
self.addEventListener('push', (event) => {
  if (!event.data) return;

  let data;
  try {
    data = event.data.json();
  } catch (e) {
    data = { title: 'Thông báo mới', body: event.data.text() };
  }

  const options = {
    body: data.body || '',
    icon: data.icon || '/icons/icon-192x192.png',
    badge: data.badge || '/icons/badge-72x72.png',
    image: data.image,
    data: data.data || {},
    tag: data.tag || 'pcms-notification',
    renotify: data.renotify ?? true,
    requireInteraction: data.requireInteraction ?? false,
    vibrate: data.vibrate || [200, 100, 200],
    actions: data.actions || [],
    dir: 'ltr',
    lang: 'vi',
    timestamp: Date.now(),
  };

  event.waitUntil(
    self.registration.showNotification(data.title || 'PCMS', options)
  );
});

// Handle notification click — open URL
self.addEventListener('notificationclick', (event) => {
  event.notification.close();

  const urlToOpen = event.notification.data?.url || '/';

  event.waitUntil(
    self.clients
      .matchAll({ type: 'window', includeUncontrolled: true })
      .then((clientList) => {
        // Check if there's already a tab open
        for (const client of clientList) {
          if (client.url.includes(self.location.origin) && 'focus' in client) {
            client.navigate(urlToOpen);
            return client.focus();
          }
        }
        // Otherwise open new tab
        if (self.clients.openWindow) {
          return self.clients.openWindow(urlToOpen);
        }
      })
  );
});

// Handle notification close (e.g., user dismisses)
self.addEventListener('notificationclose', (event) => {
  // Optional: track analytics for dismiss rate
  // console.log('Notification dismissed:', event.notification.tag);
});
